137	job_list_sort (job_list * list, job_list * end)
138	{
139	
140	  job_list *pivot, *tmp, *next, *before, *after;
141	
142	  if (list != end && list->next != end) {
143	
144	    pivot = list;
145	    before = pivot;
146	    after = end;
147	
148	    for (tmp = list->next; tmp != end; tmp = next) {
149	      next = tmp->next;
150	
151	      if (tmp->pair->next_event_t > pivot->pair->next_event_t)
152	        tmp->next = after, after = tmp;
153	      else
154	        tmp->next = before, before = tmp;
155	    }
156	
157	    before = job_list_sort (before, pivot);
158	    after = job_list_sort (after, end);
159	
160	    pivot->next = after;
161	    return before;
162	  }
163	
164	  return list;
